What does this program print?

```cpp
#include <iostream>
#include <vector>

int main()
{
    std::vector<bool> v(4, false);
    v[1] = true;
    v[3] = true;
    for (int i = 0; i < (int)v.size(); ++i)
        std::cout << v[i];
    std::cout << '\n';
}
```

This code tries to count how many `true` values are in a `std::vector<bool>`, but it has a subtle issue:

```cpp
#include <iostream>
#include <vector>

int countTrue(const std::vector<bool>& v)
{
    int count = 0;
    for (bool& b : v)    // problem here
        if (b) ++count;
    return count;
}

int main()
{
    std::vector<bool> v = {true, false, true, true};
    std::cout << countTrue(v) << '\n';
}
```
